-- ============================================================
-- Emirates Airline Database
-- Tables: passengers, flights, bookings, aircraft, crew
-- ============================================================

-- Drop existing tables if re-running
DROP TABLE IF EXISTS bookings CASCADE;
DROP TABLE IF EXISTS flights CASCADE;
DROP TABLE IF EXISTS passengers CASCADE;
DROP TABLE IF EXISTS aircraft CASCADE;
DROP TABLE IF EXISTS crew CASCADE;

-- ============================================================
-- TABLE 1: aircraft
-- ============================================================
CREATE TABLE aircraft (
    aircraft_id     SERIAL PRIMARY KEY,
    registration    VARCHAR(10) UNIQUE NOT NULL,
    model           VARCHAR(50) NOT NULL,
    manufacturer    VARCHAR(50) NOT NULL,
    total_seats     INT NOT NULL,
    business_seats  INT NOT NULL,
    economy_seats   INT NOT NULL,
    first_class_seats INT NOT NULL,
    year_manufactured INT NOT NULL,
    status          VARCHAR(20) NOT NULL DEFAULT 'active',
    last_maintenance DATE,
    base_airport    VARCHAR(5) NOT NULL
);


-- ============================================================
-- TABLE 2: passengers
-- ============================================================
CREATE TABLE passengers (
    passenger_id    SERIAL PRIMARY KEY,
    first_name      VARCHAR(50) NOT NULL,
    last_name       VARCHAR(50) NOT NULL,
    email           VARCHAR(100) UNIQUE NOT NULL,
    phone           VARCHAR(20),
    passport_number VARCHAR(20) UNIQUE NOT NULL,
    nationality     VARCHAR(50) NOT NULL,
    date_of_birth   DATE NOT NULL,
    gender          VARCHAR(10) NOT NULL,
    skywards_number VARCHAR(20),
    skywards_tier   VARCHAR(20) DEFAULT 'Blue',
    total_miles     INT DEFAULT 0,
    created_at      TIMESTAMP DEFAULT NOW()
);


-- ============================================================
-- TABLE 3: flights
-- ============================================================
CREATE TABLE flights (
    flight_id           SERIAL PRIMARY KEY,
    flight_number       VARCHAR(10) UNIQUE NOT NULL,
    aircraft_id         INT REFERENCES aircraft(aircraft_id),
    origin              VARCHAR(5) NOT NULL,
    destination         VARCHAR(5) NOT NULL,
    scheduled_departure TIMESTAMP NOT NULL,
    scheduled_arrival   TIMESTAMP NOT NULL,
    actual_departure    TIMESTAMP,
    actual_arrival      TIMESTAMP,
    status              VARCHAR(20) NOT NULL DEFAULT 'scheduled',
    gate                VARCHAR(10),
    terminal            VARCHAR(5),
    distance_km         INT NOT NULL,
    base_fare_economy   NUMERIC(10,2) NOT NULL,
    base_fare_business  NUMERIC(10,2) NOT NULL,
    base_fare_first     NUMERIC(10,2) NOT NULL
);


-- ============================================================
-- TABLE 4: bookings
-- ============================================================
CREATE TABLE bookings (
    booking_id      SERIAL PRIMARY KEY,
    booking_ref     VARCHAR(10) UNIQUE NOT NULL,
    passenger_id    INT REFERENCES passengers(passenger_id),
    flight_id       INT REFERENCES flights(flight_id),
    cabin_class     VARCHAR(20) NOT NULL,
    seat_number     VARCHAR(5),
    fare_paid       NUMERIC(10,2) NOT NULL,
    taxes           NUMERIC(10,2) NOT NULL,
    total_paid      NUMERIC(10,2) NOT NULL,
    booking_status  VARCHAR(20) NOT NULL DEFAULT 'confirmed',
    payment_method  VARCHAR(30) NOT NULL,
    booked_at       TIMESTAMP NOT NULL,
    check_in_time   TIMESTAMP,
    baggage_kg      INT DEFAULT 30,
    meal_preference VARCHAR(30) DEFAULT 'standard',
    miles_earned    INT DEFAULT 0
);


-- ============================================================
-- TABLE 5: crew
-- ============================================================
CREATE TABLE crew (
    crew_id         SERIAL PRIMARY KEY,
    employee_id     VARCHAR(10) UNIQUE NOT NULL,
    first_name      VARCHAR(50) NOT NULL,
    last_name       VARCHAR(50) NOT NULL,
    role            VARCHAR(30) NOT NULL,
    nationality     VARCHAR(50) NOT NULL,
    date_of_birth   DATE NOT NULL,
    gender          VARCHAR(10) NOT NULL,
    email           VARCHAR(100) UNIQUE NOT NULL,
    phone           VARCHAR(20),
    base_airport    VARCHAR(5) DEFAULT 'DXB',
    hire_date       DATE NOT NULL,
    license_number  VARCHAR(30),
    license_expiry  DATE,
    flight_hours    INT DEFAULT 0,
    status          VARCHAR(20) DEFAULT 'active',
    salary_aed      NUMERIC(10,2) NOT NULL,
    assigned_flight INT REFERENCES flights(flight_id)
);


-- ============================================================
-- VERIFICATION QUERIES
-- ============================================================
SELECT 'aircraft' as table_name, COUNT(*) as row_count FROM aircraft
UNION ALL
SELECT 'passengers', COUNT(*) FROM passengers
UNION ALL
SELECT 'flights', COUNT(*) FROM flights
UNION ALL
SELECT 'bookings', COUNT(*) FROM bookings
UNION ALL
SELECT 'crew', COUNT(*) FROM crew;